def solve(s: String, order: Array[Long], k: Long): Long = {
  val n = s.length
  val replaced = Array.fill(n)(false)
  var totalValid = 0L

  def countValidSubstrings(): Unit = {
    totalValid = 0L
    val stars = scala.collection.mutable.ListBuffer[Long]()
    for (i <- 0 until n) {
      if (replaced(i)) stars += i
    }

    val totalSubstrings = n * (n + 1) / 2
    var noStarSubstrings = 0L
    var start = 0L
    for (i <- 0 until n) {
      if (replaced(i)) {
        val end = i - 1
        if (start <= end) {
          val length = end - start + 1
          noStarSubstrings += length * (length + 1) / 2
        }
        start = i + 1
      }
    }
    if (start <= n - 1) {
      val length = (n - 1) - start + 1
      noStarSubstrings += length * (length + 1) / 2
    }
    totalValid = totalSubstrings - noStarSubstrings
  }

  for (t <- 0 until n) {
    val idx = order(t).toInt
    if (!replaced(idx)) {
      replaced(idx) = true
      countValidSubstrings()
      if (totalValid >= k) return t.toLong
    }
  }
  -1L
}
